// Build a clean post index for link analysis
const posts = $input.all().map(item => item.json);

const postIndex = posts.map(post => {
  // Strip HTML tags from content for keyword extraction
  const rawContent = (post.content?.rendered || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  const rawExcerpt = (post.excerpt?.rendered || '').replace(/<[^>]+>/g, ' ').trim();

  // Extract meaningful keywords from title (most important)
  const titleWords = (post.title?.rendered || '')
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .split(/\s+/)
    .filter(w => w.length > 3)
    .filter(w => !['with', 'that', 'this', 'your', 'from', 'have', 'will', 'been', 'they', 'what', 'when', 'which', 'into', 'about', 'more', 'than'].includes(w));

  // Build keyphrases (2-3 word combinations from title)
  const keyphrases = [];
  for (let i = 0; i < titleWords.length - 1; i++) {
    keyphrases.push(`${titleWords[i]} ${titleWords[i+1]}`);
    if (i < titleWords.length - 2) {
      keyphrases.push(`${titleWords[i]} ${titleWords[i+1]} ${titleWords[i+2]}`);
    }
  }

  return {
    id: post.id,
    title: post.title?.rendered || '',
    slug: post.slug,
    url: post.link,
    content_text: rawContent.substring(0, 5000), // First 5000 chars for analysis
    excerpt: rawExcerpt,
    title_keywords: titleWords,
    keyphrases: keyphrases,
    word_count: rawContent.split(/\s+/).length,
    existing_internal_links: (post.content?.rendered || '').match(/href="https?:\/\/clearstackstudio\.com[^"]*"/g) || [],
    date: post.date
  };
});

// Sort by date (newest first)
postIndex.sort((a, b) => new Date(b.date) - new Date(a.date));

console.log(`Built index of ${postIndex.length} posts`);

return [{ json: {
  post_index: postIndex,
  total_posts: postIndex.length,
  analysis_timestamp: new Date().toISOString()
}}];

const raw = $input.first().json;
const postIndex = $('⚙️ Build Post Index + Extract Keywords').first().json.post_index;

let linkData;
try {
  const content = raw?.message?.content || raw?.response || '';
  const match = content.match(/```json\n?([\s\S]*?)\n?```/) || content.match(/({[\s\S]*})/);
  linkData = JSON.parse((match ? match[1] || match[0] : content).trim());
} catch(e) {
  linkData = { link_suggestions: [], summary: 'Parse error: ' + e.message };
}

const suggestions = linkData.link_suggestions || [];

// Separate auto-insertable (high confidence) from review-needed (medium)
const autoInsert = suggestions.filter(s => s.auto_insert && s.confidence === 'high');
const needsReview = suggestions.filter(s => !s.auto_insert || s.confidence === 'medium');

console.log(`Total suggestions: ${suggestions.length} | Auto-insert: ${autoInsert.length} | Review needed: ${needsReview.length}`);

return [{ json: {
  all_suggestions: suggestions,
  auto_insert: autoInsert,
  needs_review: needsReview,
  auto_insert_count: autoInsert.length,
  review_count: needsReview.length,
  posts_needing_links: linkData.posts_needing_links || [],
  summary: linkData.summary || '',
  post_index: postIndex,
  _parsed: true
}}];

// For each auto-insert suggestion, fetch the source post content
// and inject the internal link
const data = $input.first().json;
const suggestions = data.auto_insert || [];

// Return each suggestion as a separate item for parallel processing
return suggestions.map(s => ({ json: {
  ...s,
  post_index: data.post_index,
  _ready_to_insert: true
}}));

// Inject the internal link into the post content
const suggestion = $('⚙️ Split Auto-Insert Jobs').first().json;
const postData = $input.first().json;

const anchorText = suggestion.suggested_anchor_text;
const targetUrl = suggestion.target_post_url;
const sourceContent = postData.content?.raw || postData.content?.rendered || '';

// Build the link HTML
const linkHtml = `<a href="${targetUrl}">${anchorText}</a>`;

// Replace FIRST occurrence of anchor text with linked version
// Only replace if not already inside an anchor tag
const alreadyLinked = sourceContent.includes(`href="${targetUrl}"`);

if (alreadyLinked) {
  return [{ json: {
    skipped: true,
    reason: 'Link already exists in post',
    post_id: suggestion.source_post_id,
    target_url: targetUrl
  }}];
}

// Case-insensitive replace of first occurrence
const anchorRegex = new RegExp(`(?<!href="[^"]*>)(?<!</a>)${anchorText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}(?![^<]*<\/a>)`, 'i');
const updatedContent = sourceContent.replace(anchorRegex, linkHtml);

if (updatedContent === sourceContent) {
  // Exact phrase not found in content — skip
  return [{ json: {
    skipped: true,
    reason: `Anchor text '${anchorText}' not found in post content`,
    post_id: suggestion.source_post_id
  }}];
}

return [{ json: {
  skipped: false,
  post_id: suggestion.source_post_id,
  post_title: suggestion.source_post_title,
  target_post_title: suggestion.target_post_title,
  target_url: targetUrl,
  anchor_text: anchorText,
  updated_content: updatedContent,
  confidence: suggestion.confidence,
  seo_reason: suggestion.seo_reason
}}];
